package result_test

import (
	"fmt"
	"testing"

	result "github.com/selfshop-dev/lib-result"
)

// indexedErr is a unique error per position in the input slice.
// This lets FuzzCollect verify that Collect returns exactly the first
// error encountered, not a later one.
type indexedErr struct{ idx int }

func (e *indexedErr) Error() string { return fmt.Sprintf("error at index %d", e.idx) }

// FuzzCollect exercises Collect against arbitrary combinations of Ok and Err
// results generated by the fuzzer.
//
// Each byte in the input slice represents one Result: zero means Err, any
// other value means Ok. This encoding lets the fuzzer mutate both the length
// and the Ok/Err pattern of the input.
//
// Invariants checked on every corpus entry:
//  1. All Ok inputs          → Collect returns Ok with the correct length and order.
//  2. At least one Err input → Collect returns Err.
//  3. The returned error is exactly the first one — not a later one.
//
// Run the fuzzer:
//
//	go test -fuzz=FuzzCollect -fuzztime=60s
//
// Run the seed corpus only (CI):
//
//	go test -run=FuzzCollect
func FuzzCollect(f *testing.F) {
	f.Add([]byte{1, 1, 1}) // All Ok.
	f.Add([]byte{0, 1, 1}) // Err at the start — short-circuits immediately.
	f.Add([]byte{1, 0, 1}) // Err in the middle.
	f.Add([]byte{1, 1, 0}) // Err at the end.
	f.Add([]byte{0, 0, 0}) // All Err — first error is at index 0.
	f.Add([]byte{1})       // Single Ok.
	f.Add([]byte{0})       // Single Err.
	f.Add([]byte{})        // Empty slice.

	f.Fuzz(func(t *testing.T, flags []byte) {
		// Each error is unique by index so we can verify Collect returns
		// exactly the first one encountered, not a later one.
		rs := make([]result.Result[int, *indexedErr], len(flags))
		firstErrIdx := -1

		for i, flag := range flags {
			if flag != 0 {
				rs[i] = result.Ok[int, *indexedErr](i)
			} else {
				rs[i] = result.Err[int](&indexedErr{idx: i})
				if firstErrIdx == -1 {
					firstErrIdx = i
				}
			}
		}

		r := result.Collect(rs)

		if firstErrIdx == -1 {
			// Invariant 1: all Ok → result must be Ok.
			if !r.IsOk() {
				t.Fatal("all Ok inputs: Collect returned Err")
			}

			vals := r.Unwrap()

			// Invariant 1a: length must match.
			if len(vals) != len(flags) {
				t.Errorf("len = %d, want %d", len(vals), len(flags))
			}

			// Invariant 1b: values must be preserved in order.
			for i, v := range vals {
				if v != i {
					t.Errorf("vals[%d] = %d, want %d", i, v, i)
				}
			}
		} else {
			// Invariant 2: at least one Err → result must be Err.
			if !r.IsErr() {
				t.Fatal("Err input present: Collect returned Ok")
			}

			// Invariant 3: must be exactly the first Err, not a later one.
			e, _ := r.Err()
			if e.idx != firstErrIdx {
				t.Errorf("returned error index = %d, want first = %d", e.idx, firstErrIdx)
			}
		}
	})
}
